mapper.update:
update recommendation
rec_type = #{recType}, content_id = #{contentId}, reason = #{reason}, score = #{score}, is_clicked = #{isClicked},
where rec_id = #{recId}

mapper.select:
select r.*, u.nickname as userName from recommendation r left join user u on r.user_id = u.user_id
and r.rec_type = #{recType}
order by r.create_time desc
